import androidx.preference.PreferenceCategory
import androidx.test.core.app.ActivityScenario
import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.R
import com.ichi2.anki.RobolectricTest
import com.ichi2.anki.cardviewer.ViewerCommand
import com.ichi2.preferences.ControlPreference
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.hamcrest.Matchers.notNullValue
import org.junit.Test
import org.junit.runner.RunWith

@RunWith(AndroidJUnit4::class)
class ControlsSettingsFragmentTest : RobolectricTest() {

    @Test
    fun verifyAllCommandsArePresent() {
        val scenario = ActivityScenario.launch(Preferences::class.java)
        scenario.onActivity { activity ->
            val fragment = ControlsSettingsFragment()
            activity.supportFragmentManager.beginTransaction()
                .replace(R.id.settings_container, fragment)
                .commitNow()

            val preferenceScreen = fragment.preferenceScreen
            assertThat(preferenceScreen, notNullValue())

            // Verify all commands are findable
            for (command in ViewerCommand.values()) {
                val pref = fragment.findPreference<ControlPreference>(command.preferenceKey)
                assertThat("Command ${command.name} should be present in preferences", pref, notNullValue())
            }

            // Verify categories exist
            val expectedCategories = listOf(
                R.string.controls_category_answer,
                R.string.controls_category_flags,
                R.string.controls_category_whiteboard,
                R.string.controls_category_current_card,
                R.string.controls_category_navigation,
                R.string.controls_category_misc
            )

            for (resId in expectedCategories) {
                val categoryTitle = activity.getString(resId)
                var found = false
                for (i in 0 until preferenceScreen.preferenceCount) {
                    val pref = preferenceScreen.getPreference(i)
                    if (pref is PreferenceCategory && pref.title == categoryTitle) {
                        found = true
                        break
                    }
                }
                assertThat("Category '$categoryTitle' should be present", found, equalTo(true))
            }
        }
    }
}
